# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.serialization.oterm_from_json","kind":"function","src_hash":"f9b92fb9f110cd25","in":{"base":"Dict[str, Any]"},"out":{"base":"OTerm"},"spec":{"lhs":"oterm_from_json(dat)","rhs":"deserialize an oterm from a json-compatible dict","over":{"base":"Dict[str, Any]"},"name":"oterm_from_json_correct"},"guarantee":"deserialize an oterm from a json-compatible dict","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.serialization.oterm_from_json_correct","statement":"Path(oterm_from_json(x), deserialize an oterm from a json-compatible dict)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"ad55b41c72760b71"}
def oterm_from_json(data: Dict[str, Any]) -> OTerm:
    """Deserialize an OTerm from a JSON-compatible dict."""
    t = data['type']

    if t == 'OVar':
        return OVar(data['name'])
    elif t == 'OLit':
        vt = data.get('value_type', 'repr')
        v = data['value']
        if vt == 'none':
            return OLit(None)
        elif vt == 'bool':
            return OLit(bool(v))
        elif vt == 'int':
            return OLit(int(v))
        elif vt == 'float':
            return OLit(float(v))
        elif vt == 'str':
            return OLit(str(v))
        else:
            return OLit(v)
    elif t == 'OOp':
        return OOp(data['name'],
                   tuple(oterm_from_json(a) for a in data['args']))
    elif t == 'OFold':
        return OFold(data['op_name'],
                     oterm_from_json(data['init']),
                     oterm_from_json(data['collection']))
    elif t == 'OCase':
        return OCase(oterm_from_json(data['test']),
                     oterm_from_json(data['true_branch']),
                     oterm_from_json(data['false_branch']))
    elif t == 'OFix':
        return OFix(data['name'], oterm_from_json(data['body']))
    elif t == 'OSeq':
        return OSeq(tuple(oterm_from_json(e) for e in data['elements']))
    elif t == 'ODict':
        return ODict(tuple((oterm_from_json(p[0]), oterm_from_json(p[1]))
                           for p in data['pairs']))
    elif t == 'OUnknown':
        return OUnknown(data['desc'])
    elif t == 'OQuotient':
        return OQuotient(oterm_from_json(data['inner']),
                         data['equiv_class'])
    elif t == 'OAbstract':
        return OAbstract(data['spec'],
                         tuple(oterm_from_json(i) for i in data['inputs']))
    elif t == 'OLam':
        return OLam(tuple(data['params']),
                    oterm_from_json(data['body']))
    elif t == 'OMap':
        fp = (oterm_from_json(data['filter_pred'])
              if 'filter_pred' in data else None)
        return OMap(oterm_from_json(data['transform']),
                    oterm_from_json(data['collection']), fp)
    elif t == 'OCatch':
        return OCatch(oterm_from_json(data['body']),
                      oterm_from_json(data['default']))
    else:
        return OUnknown(f'deserialization_error:{t}')


