# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.serialization.proof_to_notation","kind":"function","src_hash":"739d92399a6f4e12","in":{"base":"ProofTerm"},"out":{"base":"str"},"spec":{"lhs":"proof_to_notation(pro)","rhs":"convert a proof term to human-readable notation","over":{"base":"ProofTerm"},"name":"proof_to_notation_correct"},"guarantee":"convert a proof term to human-readable notation","fibers":[],"h1":0,"paths":[],"strategy":"refl","details":{},"assumes":[],"trust":["lean.C4.Reduction.ReducesStar.refl"],"compiled":true,"vhash":"787988377d37f6aa"}
def proof_to_notation(proof: ProofTerm) -> str:
    """Convert a proof term to human-readable notation.

    Example output::

        proof factorial_equiv : fact_rec(n) ≡ fact_iter(n)
        by nat_induction on n:
          base: refl(1)
          step:
            trans via n * fact_rec(n-1):
              δ(fact_rec)
              cong[*](refl(n), IH_n)
    """
    return proof.pretty(indent=0)


