# ║ 🟢 KERNEL | library_axiom | Compiled: ✓ | bb61414d255bbcb0  ║
# ╚════════════════════════════════════════════════════════════╝
# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.serialization.document_to_notation","kind":"function","src_hash":"50612da40adb62fe","in":{"base":"ProofDocument"},"out":{"base":"str"},"spec":{"lhs":"document_to_notation(doc)","rhs":"convert a proof document to human-readable notation","over":{"base":"ProofDocument"},"name":"document_to_notation_correct"},"guarantee":"convert a proof document to human-readable notation","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.serialization.document_to_notation_correct","statement":"Path(document_to_notation(x), convert a proof document to human-readable notation)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"bb61414d255bbcb0"}
def document_to_notation(doc: ProofDocument) -> str:
    """Convert a proof document to human-readable notation."""
    lines = [
        f'-- {doc.description}' if doc.description else '',
        f'-- strategy: {doc.strategy}' if doc.strategy else '',
        f'proof {doc.name} : {doc.lhs.canon()} ≡ {doc.rhs.canon()}',
        proof_to_notation(doc.proof),
    ]
    return '\n'.join(line for line in lines if line)
